/// 内核入口
#[no_mangle]
pub fn rust_main() -> ! {
    clear_bss();
    print_memory_map();
    print_banner();
    info!("[KERNEL] Hello, world!");

    info!("[KERNEL] Initializing trap...");
    trap::init();

    info!("[KERNEL] Initializing batch...");
    batch::init();

    info!("[KERNEL] Running first app...");
    batch::run_next_app();
}

fn clear_bss() {
    extern "C" {
        fn sbss();
        fn ebss();
    }
    let start = sbss as *const () as usize;
    let end = ebss as *const () as usize;
    for a in (start..end).step_by(8) {
        unsafe {
            (a as *mut u64).write_volatile(0);
        }
    }
}

/*确保进入程序符号是_start，并确保内核从物理地址0x80200000放置*/
OUTPUT_ARCH(riscv)
ENTRY(_start)
BASE_ADDRESS = 0x80200000;

SECTIONS
{
    . = BASE_ADDRESS;
    skernel = .;

    stext = .;
    .text : {
        *(.text.entry)
        *(.text .text.*)
    }

    . = ALIGN(4K);
    etext = .;
    srodata = .;
    .rodata : {
        *(.rodata .rodata.*)
        *(.srodata .srodata.*)
        *(.rodata.apps)
    }

    . = ALIGN(4K);
    erodata = .;
    sdata = .;
    .data : {
        *(.data .data.*)
        *(.sdata .sdata.*)
        *(.data.apps)
    }

    . = ALIGN(4K);
    edata = .;
    .bss : {
        *(.bss.stack)
        sbss = .;
        *(.bss .bss.*)
        *(.sbss .sbss.*)
    }

    . = ALIGN(4K);
    ebss = .;
    ekernel = .;

    /DISCARD/ : {
        *(.eh_frame)
    }
}

