// 增强 panic handler：寄存器 dump + 栈回溯

use core::arch::asm;
use core::panic::PanicInfo;
use crate::sbi::shutdown;
use crate::utils::panic::{Registers, print_registers, print_backtrace};
use crate::{println, error};

#[panic_handler]
fn panic(info: &PanicInfo) -> ! {
    // ---- 1. 捕获寄存器快照 ----
    // 拆分为多个小块，避免 "requires more registers than available"
    let mut regs = Registers::zeroed();
    unsafe {
        asm!(
            "mv {ra}, ra", "mv {sp}, sp", "mv {gp}, gp", "mv {tp}, tp",
            ra = out(reg) regs.ra, sp = out(reg) regs.sp,
            gp = out(reg) regs.gp, tp = out(reg) regs.tp,
        );
        asm!(
            "mv {t0}, t0", "mv {t1}, t1", "mv {t2}, t2",
            "mv {s0}, s0", "mv {s1}, s1",
            "mv {a0}, a0", "mv {a1}, a1",
            t0 = out(reg) regs.t0, t1 = out(reg) regs.t1, t2 = out(reg) regs.t2,
            s0 = out(reg) regs.s0, s1 = out(reg) regs.s1,
            a0 = out(reg) regs.a0, a1 = out(reg) regs.a1,
        );
        asm!(
            "mv {a2}, a2", "mv {a3}, a3", "mv {a4}, a4", "mv {a5}, a5",
            "mv {a6}, a6", "mv {a7}, a7",
            a2 = out(reg) regs.a2, a3 = out(reg) regs.a3,
            a4 = out(reg) regs.a4, a5 = out(reg) regs.a5,
            a6 = out(reg) regs.a6, a7 = out(reg) regs.a7,
        );
        asm!(
            "mv {s2}, s2", "mv {s3}, s3", "mv {s4}, s4", "mv {s5}, s5",
            "mv {s6}, s6", "mv {s7}, s7",
            s2 = out(reg) regs.s2, s3 = out(reg) regs.s3,
            s4 = out(reg) regs.s4, s5 = out(reg) regs.s5,
            s6 = out(reg) regs.s6, s7 = out(reg) regs.s7,
        );
        asm!(
            "mv {s8}, s8", "mv {s9}, s9", "mv {s10}, s10", "mv {s11}, s11",
            s8 = out(reg) regs.s8, s9 = out(reg) regs.s9,
            s10 = out(reg) regs.s10, s11 = out(reg) regs.s11,
        );
        asm!(
            "mv {t3}, t3", "mv {t4}, t4", "mv {t5}, t5", "mv {t6}, t6",
            t3 = out(reg) regs.t3, t4 = out(reg) regs.t4,
            t5 = out(reg) regs.t5, t6 = out(reg) regs.t6,
        );
        asm!(
            "csrr {sepc}, sepc", "csrr {scause}, scause",
            "csrr {stval}, stval", "csrr {sstatus}, sstatus",
            sepc = out(reg) regs.sepc, scause = out(reg) regs.scause,
            stval = out(reg) regs.stval, sstatus = out(reg) regs.sstatus,
        );
    }

    // ---- 2. 打印 panic 信息 ----
    error!("=== KERNEL PANIC ===");
    if let Some(loc) = info.location() {
        println!("at {}:{}", loc.file(), loc.line());
    }
    println!("message: {}", info.message());

    // ---- 3. 打印寄存器 ----
    error!("=== REGISTERS ===");
    print_registers(&regs);

    // ---- 4. 打印栈回溯 ----
    error!("=== STACK BACKTRACE ===");
    print_backtrace(regs.s0);

    // ---- 5. 关机 ----
    shutdown(true)
}

