/// 初始化 Trap 处理
pub fn init() {
    extern "C" {
        fn __alltraps();
    }
    unsafe {
        // sscratch 初始化为 0（首次 csrrw 时交换）
        core::arch::asm!("csrw sscratch, zero");
        // 设置 stvec = __alltraps (Direct 模式)
        core::arch::asm!("csrw stvec, {}", in(reg) __alltraps as *const () as usize);
    }
}

use crate::trap::context::TrapContext;
use crate::{batch, syscall};

/// Trap 原因常量
const USER_ENV_CALL: usize = 8;
const INSTRUCTION_FAULT: usize = 1;
const ILLEGAL_INSTRUCTION: usize = 2;
const STORE_FAULT: usize = 7;
const INSTRUCTION_PAGE_FAULT: usize = 12;
const LOAD_PAGE_FAULT: usize = 13;
const STORE_PAGE_FAULT: usize = 15;

/// Trap 处理入口（从 __alltraps 汇编调用）
#[no_mangle]
pub extern "C" fn trap_handler(cx: &mut TrapContext) {
    let scause: usize;
    unsafe {
        core::arch::asm!("csrr {}, scause", out(reg) scause);
    }

    let cause = scause & 0xff;
    let is_interrupt = (scause >> 63) != 0;

    if is_interrupt {
        panic!("unexpected interrupt: cause={}", cause);
    }

    match cause {
        USER_ENV_CALL => {
            // ecall: 系统调用
            cx.sepc += 4;
            let id = cx.x[17]; // a7
            let args = [cx.x[10], cx.x[11], cx.x[12]]; // a0, a1, a2
            cx.x[10] = syscall::syscall(id, args) as usize;
        }
        INSTRUCTION_FAULT | INSTRUCTION_PAGE_FAULT | LOAD_PAGE_FAULT
        | STORE_FAULT | STORE_PAGE_FAULT | ILLEGAL_INSTRUCTION => {
            crate::println!(
                "[KERNEL] App exception, cause={}, sepc={:#x}, killed.",
                cause, cx.sepc
            );
            batch::run_next_app()
        }
        9 => panic!("ecall from S-mode — kernel bug"),
        _ => {
            crate::println!(
                "[KERNEL] Unknown trap: cause={}, sepc={:#x}",
                cause, cx.sepc
            );
            batch::run_next_app()
        }
    }
}

#![allow(dead_code)]

/// 用户态和内核态之间切换时需要保存的 CPU 状态
#[repr(C)]
pub struct TrapContext {
    /// 通用寄存器 x0-x31（x0 硬连线为 0，占位）
    pub x: [usize; 32],
    /// Supervisor Status Register
    pub sstatus: usize,
    /// Supervisor Exception Program Counter
    pub sepc: usize,
    /// 内核页表地址（暂未使用）
    pub kernel_satp: usize,
    /// 内核栈指针
    pub kernel_sp: usize,
    /// trap_handler 函数地址
    pub trap_handler: usize,
}

impl TrapContext {
    /// 为应用程序创建初始 TrapContext
    /// - entry: 用户程序入口地址
    /// - sp: 用户栈栈顶
    pub fn app_init(entry: usize, sp: usize) -> Self {
        let mut cx = Self {
            x: [0; 32],
            sstatus: 1 << 5, // SPIE = 1 (开启中断), SPP = 0 (User mode)
            sepc: entry,
            kernel_satp: 0,
            kernel_sp: 0,
            trap_handler: 0, // 由调用者设置
        };
        cx.x[2] = sp; // x2 = sp
        cx
    }
}

use crate::trap::context::TrapContext;

const USER_STACK_BASE: usize = 0x80500000;
const USER_STACK_SIZE: usize = 4096 * 16;
const APP_BASE: usize = 0x80400000;

static mut CURRENT: usize = 0;
static mut COUNT: usize = 0;

extern "C" {
    fn _app_count();
    fn _app_list();
    fn __restore();
}

/// 初始化批处理系统
pub fn init() {
    unsafe {
        let ptr = _app_count as *const () as *const u64;
        COUNT = core::ptr::read_volatile(ptr) as usize;
    }
    crate::println!("[KERNEL] Found {} apps", unsafe { COUNT });
}

pub fn current_pid() -> usize {
    unsafe { CURRENT }
}

fn get_app_info(idx: usize) -> (usize, usize) {
    assert!(idx < unsafe { COUNT }, "app index out of bounds");
    unsafe {
        let list = _app_list as *const () as *const u64;
        let start = core::ptr::read_volatile(list.add(idx)) as usize;
        let end = core::ptr::read_volatile(list.add(idx + 1)) as usize;
        let size = end - start;
        (start, size)
    }
}

/// 加载并运行下一个应用程序
pub fn run_next_app() -> ! {
    let count = unsafe { COUNT };
    let idx = unsafe { CURRENT };

    if idx >= count {
        crate::println!("[KERNEL] All {} apps done, shutdown.", count);
        crate::sbi::shutdown(false);
    }

    unsafe { CURRENT = idx + 1; }

    let (start, size) = get_app_info(idx);
    crate::println!(
        "[KERNEL] Loading app {} start={:#x} size={:#x}",
        idx, start, size
    );

    // 复制应用代码到用户地址空间
    let dst = APP_BASE as *mut u8;
    let src = start as *const u8;
    unsafe {
        for i in 0..size {
            dst.add(i).write_volatile(src.add(i).read());
        }
        // 保证指令缓存看到新写入的代码
        core::arch::asm!("fence.i");
    }

    // 配置 TrapContext
    let sp = USER_STACK_BASE - USER_STACK_SIZE;
    let mut cx = TrapContext::app_init(APP_BASE, sp);

    // 设置内核栈
    extern "C" {
        fn kernel_trap_stack_top();
    }
    cx.kernel_sp = kernel_trap_stack_top as *const () as usize;
    cx.trap_handler = crate::trap::handler::trap_handler as *const () as usize;

    // 设置 sscratch = TrapContext 地址
    let cx_ptr = &cx as *const _ as usize;
    unsafe {
        core::arch::asm!("csrw sscratch, {}", in(reg) cx_ptr);
    }

    // 跳转到 __restore 恢复上下文并 sret 到用户态
    crate::println!("[KERNEL] Jumping to user mode at {:#x}", APP_BASE);
    unsafe {
        let restore: extern "C" fn(usize) -> ! =
            core::mem::transmute(__restore as *const ());
        restore(cx_ptr);
    }
}

