// Panic 增强：寄存器快照 + 栈回溯
// println! 宏由 #[macro_export] 自动可用，无需 use

/// 寄存器快照 — 在 panic 入口通过 asm! 捕获
#[repr(C)]
pub struct Registers {
    // === 通用寄存器 x1-x31 ===
    pub ra: usize, // x1  返回地址
    pub sp: usize, // x2  栈指针
    pub gp: usize, // x3  全局指针
    pub tp: usize, // x4  线程指针
    pub t0: usize,
    pub t1: usize,
    pub t2: usize, // x5-x7 临时
    pub s0: usize, // x8  帧指针 (fp)
    pub s1: usize, // x9  保存寄存器
    pub a0: usize,
    pub a1: usize, // x10-x11 参数/返回值 (panic 时已被覆盖, 打印供参考)
    pub a2: usize,
    pub a3: usize,
    pub a4: usize,
    pub a5: usize,
    pub a6: usize,
    pub a7: usize, // x12-x17
    pub s2: usize,
    pub s3: usize,
    pub s4: usize,
    pub s5: usize,
    pub s6: usize,
    pub s7: usize,
    pub s8: usize,
    pub s9: usize,
    pub s10: usize,
    pub s11: usize, // x18-x27
    pub t3: usize,
    pub t4: usize,
    pub t5: usize,
    pub t6: usize, // x28-x31

    // === 关键 CSR (S-mode) ===
    pub sepc: usize,    // 异常 PC
    pub scause: usize,  // 异常原因
    pub stval: usize,   // 异常附加信息
    pub sstatus: usize, // 特权状态
}

impl Registers {
    /// 全部字段置零的初始值 (x0 语义)
    pub const fn zeroed() -> Self {
        Self {
            ra: 0, sp: 0, gp: 0, tp: 0,
            t0: 0, t1: 0, t2: 0,
            s0: 0, s1: 0,
            a0: 0, a1: 0, a2: 0, a3: 0, a4: 0, a5: 0, a6: 0, a7: 0,
            s2: 0, s3: 0, s4: 0, s5: 0,
            s6: 0, s7: 0, s8: 0, s9: 0, s10: 0, s11: 0,
            t3: 0, t4: 0, t5: 0, t6: 0,
            sepc: 0, scause: 0, stval: 0, sstatus: 0,
        }
    }
}

/// 格式化打印所有寄存器和 CSR
pub fn print_registers(r: &Registers) {
    // ----- x regs -----
    println!("x0/zero  {:#018x}  x1/ra  {:#018x}  x2/sp  {:#018x}  x3/gp  {:#018x}",
             0usize, r.ra, r.sp, r.gp);
    println!("x4/tp  {:#018x}  x5/t0  {:#018x}  x6/t1  {:#018x}  x7/t2  {:#018x}",
             r.tp, r.t0, r.t1, r.t2);
    println!("x8/s0  {:#018x}  x9/s1  {:#018x}  x10/a0 {:#018x}  x11/a1 {:#018x}",
             r.s0, r.s1, r.a0, r.a1);
    println!("x12/a2 {:#018x}  x13/a3 {:#018x}  x14/a4 {:#018x}  x15/a5 {:#018x}",
             r.a2, r.a3, r.a4, r.a5);
    println!("x16/a6 {:#018x}  x17/a7 {:#018x}  x18/s2 {:#018x}  x19/s3 {:#018x}",
             r.a6, r.a7, r.s2, r.s3);
    println!("x20/s4 {:#018x}  x21/s5 {:#018x}  x22/s6 {:#018x}  x23/s7 {:#018x}",
             r.s4, r.s5, r.s6, r.s7);
    println!("x24/s8 {:#018x}  x25/s9 {:#018x}  x26/s10 {:#018x} x27/s11 {:#018x}",
             r.s8, r.s9, r.s10, r.s11);
    println!("x28/t3 {:#018x}  x29/t4 {:#018x}  x30/t5 {:#018x}  x31/t6 {:#018x}",
             r.t3, r.t4, r.t5, r.t6);
    // ----- CSRs -----
    println!("sepc    {:#018x}  scause  {:#018x}  stval   {:#018x}  sstatus {:#018x}",
             r.sepc, r.scause, r.stval, r.sstatus);
}

/// 帧指针链栈回溯
///
/// 从当前 s0 (fp) 开始，沿帧指针链回溯调用栈。
/// 依赖 `-Cforce-frame-pointers=yes`。
pub fn print_backtrace(mut fp: usize) {
    extern "C" {
        fn stext();
        fn etext();
        fn boot_stack_lower_bound();
        fn boot_stack_top();
    }

    let text_start = stext as *const () as usize;
    let text_end = etext as *const () as usize;
    let stack_bottom = boot_stack_lower_bound as *const () as usize;
    let stack_top = boot_stack_top as *const () as usize;

    let mut depth = 0;
    const MAX_DEPTH: usize = 32;

    while fp != 0
        && fp >= stack_bottom
        && fp < stack_top
        && depth < MAX_DEPTH
    {
        // LLVM with -Cforce-frame-pointers=yes:
        //   addi sp, sp, -N
        //   sd ra, N-8(sp)
        //   sd s0, N-16(sp)
        //   addi s0, sp, N
        // So: fp (=s0) points to frame base, saved_ra at fp-8, saved_s0 at fp-16
        let ra = unsafe { *((fp - 8) as *const usize) };
        let prev_fp = unsafe { *((fp - 16) as *const usize) };

        if ra < text_start || ra >= text_end {
            break;
        }

        println!("  #{}  {:#018x}", depth, ra);
        fp = prev_fp;
        depth += 1;
    }

    if depth == 0 {
        println!("  (no backtrace)");
    } else {
        println!("  backtrace: {} frames", depth);
    }
}

use std::fs::{read_dir, File};
use std::io::{Result, Write};
use std::process::Command;

fn main() {
    // === 原有逻辑：获取编译时间和 Git commit ===
    let build_time = chrono::Local::now().format("%Y-%m-%d %H:%M:%S").to_string();
    println!("cargo:rustc-env=BUILD_TIME={}", build_time);

    let git_commit = Command::new("git")
        .args(&["rev-parse", "--short", "HEAD"])
        .output()
        .map(|output| String::from_utf8(output.stdout).unwrap_or_default())
        .unwrap_or_else(|_| "unknown".to_string());
    println!("cargo:rustc-env=GIT_COMMIT={}", git_commit.trim());

    // === 新增逻辑：自动生成 link_app.S ===
    insert_app_data().expect("Failed to generate link_app.S");

    // 告诉 Cargo，如果 user/src/bin 里的应用代码变了，就重新执行 build.rs
    println!("cargo:rerun-if-changed=user/src/bin/");
}

/// 自动扫描 user/src/bin 目录，并将生成的二进制程序通过汇编链接到内核数据段
fn insert_app_data() -> Result<()> {
    let mut f = File::create("src/link_app.S")?;

    // 1. 获取所有应用名称（去掉 .rs 后缀）
    let mut apps: Vec<_> = read_dir("user/src/bin")?
        .into_iter()
        .map(|dir_entry| {
            let mut name_with_ext = dir_entry.unwrap().file_name().into_string().unwrap();
            name_with_ext.drain(name_with_ext.find('.').unwrap()..name_with_ext.len());
            name_with_ext
        })
        .collect();
    apps.sort();

    // 2. 写入全局应用数量 (修改为匹配你们内核的 _app_count)
    writeln!(f, r#"
    .align 3
    .section .data
    .global _app_count
_app_count:
    .quad {}"#, apps.len())?;

    // 3. 写入起止地址指针数组 (新增并匹配你们内核的 _app_list)
    writeln!(f, r#"
    .global _app_list
_app_list:"#)?;
    for i in 0..apps.len() {
        writeln!(f, r#"    .quad app_{}_start"#, i)?;
    }
    writeln!(f, r#"    .quad app_{}_end"#, apps.len() - 1)?;

    // 4. 遍历所有应用，先使用 rust-objcopy 转为纯净二进制 (.bin)，再用 .incbin 引入
    for (idx, app) in apps.iter().enumerate() {
        println!("app_{}: {}", idx, app);

        // 获取原 ELF 文件路径和目标 BIN 文件路径
        let elf_path = format!("user/target/riscv64gc-unknown-none-elf/release/{}", app);
        let bin_path = format!("user/target/riscv64gc-unknown-none-elf/release/{}.bin", app);

        // 新增：调用 rust-objcopy 进行脱壳
        let status = std::process::Command::new("rust-objcopy")
            .arg("--strip-all")
            .arg("-O")
            .arg("binary")
            .arg(&elf_path)
            .arg(&bin_path)
            .status()
            .expect("Failed to execute rust-objcopy");

        if !status.success() {
            panic!("rust-objcopy failed for app: {}", app);
        }

        // 注意这里：.incbin 引入的变成了剥离后的 {}.bin 文件
        writeln!(f, r#"
    .section .data
    .global app_{0}_start
    .global app_{0}_end
app_{0}_start:
    .incbin "{1}"
app_{0}_end:"#, idx, bin_path)?;
    }

    Ok(())
}

