    ($($arg:tt)*) => ({
        $crate::print(core::format_args!($($arg)*));
    });
}

/// println! 宏
#[macro_export]
macro_rules! println {
    () => ({
        $crate::print(core::format_args!("\n"));
    });

    ($fmt:expr) => ({
        $crate::print(core::format_args!(concat!($fmt, "\n")));
    });

    ($fmt:expr, $($arg:tt)*) => ({
        $crate::print(core::format_args!(
            concat!($fmt, "\n"),
            $($arg)*
        ));
    });
}

