use core::arch::asm;

pub const SYS_WRITE: usize = 64;
pub const SYS_EXIT: usize = 93;
pub const SYS_GETPID: usize = 172;
pub const SYS_YIELD: usize = 124;

#[inline]
pub fn sys_write(fd: usize, buf: *const u8, len: usize) -> isize {
    let ret: isize;
    unsafe {
        asm!("ecall",
            inlateout("a0") fd => ret,
            in("a1") buf,
            in("a2") len,
            in("a7") SYS_WRITE,
        );
    }
    ret
}

pub fn sys_exit(code: i32) -> ! {
    unsafe {
        asm!("ecall",
            in("a0") code,
            in("a7") SYS_EXIT,
            options(noreturn)
        );
    }
}

pub fn sys_getpid() -> isize {
    let ret: isize;
    unsafe {
        asm!("ecall",
            in("a7") SYS_GETPID,
            lateout("a0") ret,
        );
    }
    ret
}

pub fn sys_yield() -> isize {
    let ret: isize;
    unsafe {
        asm!("ecall",
            in("a7") SYS_YIELD,
            lateout("a0") ret,
        );
    }
    ret
}

