/// 栈上 u64 → 十进制字符串（no_std 环境自实现，无需 alloc）
fn format_u64(n: u64, buf: &mut [u8]) -> &[u8] {
    let len = buf.len();
    let mut val = n;
    let mut pos = len;
    if val == 0 {
        pos -= 1;
        buf[pos] = b'0';
    } else {
        while val > 0 && pos > 0 {
            pos -= 1;
            buf[pos] = (val % 10) as u8 + b'0';
            val /= 10;
        }
    }
    &buf[pos..]
}

