const N: usize = 15;

fn format_u64(n: u64, buf: &mut [u8]) -> &[u8] {
    let len = buf.len();
    let mut val = n;
    let mut pos = len;
    if val == 0 {
        pos -= 1;
        buf[pos] = b'0';
    } else {
        while val > 0 && pos > 0 {
            pos -= 1;
            buf[pos] = (val % 10) as u8 + b'0';
            val /= 10;
        }
    }
    &buf[pos..]
}

#[link_section = ".text.entry"]
#[no_mangle]
pub extern "C" fn _start() -> ! {
    let msg = "Fibonacci (first 15):\n";
    sys_write(1, msg.as_ptr(), msg.len());

    let mut a: u64 = 0;
    let mut b: u64 = 1;
    let mut buf: [u8; 20] = [0; 20];

    for _ in 0..N {
        let s = format_u64(a, &mut buf);
        sys_write(1, s.as_ptr(), s.len());
        sys_write(1, b"\n" as *const u8, 1);

        let next = a.wrapping_add(b);
        a = b;
        b = next;
    }

    sys_exit(0);
}

