#!/usr/bin/env python3
"""清理 vendor 中的隐藏文件/目录，重写 checksum，确保离线编译兼容"""
import os, json, shutil

VENDOR = os.path.join(os.path.dirname(os.path.abspath(__file__)), "..", "vendor")

for crate in sorted(os.listdir(VENDOR)):
    crate_dir = os.path.join(VENDOR, crate)
    if not os.path.isdir(crate_dir) or crate.startswith("."):
        continue

    for name in os.listdir(crate_dir):
        if name.startswith("."):
            path = os.path.join(crate_dir, name)
            if os.path.isdir(path):
                shutil.rmtree(path)
            elif name != ".cargo-checksum.json":
                os.remove(path)

    for root, dirs, files in os.walk(crate_dir):
        dirs[:] = [d for d in dirs if not d.startswith(".")]
        for f in files:
            if f.startswith(".") and f != ".cargo-checksum.json":
                os.remove(os.path.join(root, f))

    checksum_path = os.path.join(crate_dir, ".cargo-checksum.json")
    if os.path.exists(checksum_path):
        with open(checksum_path) as f:
            data = json.load(f)
        data["files"] = {
            k: v for k, v in data.get("files", {}).items()
            if not any(part.startswith(".") for part in k.split("/"))
        }
        with open(checksum_path, "w") as f:
            json.dump(data, f, indent=2)
            f.write("\n")

print("vendor cleanup complete")

